  "inlineSchema": "// ================================\n// PONTOFACIL - SCHEMA DO BANCO DE DADOS\n// Multi-tenant com Row-Level Security\n// ================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  // Runtime (ex.: pooler Supabase :6543 + ?pgbouncer=true). Migrações usam directUrl.\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// ---- EMPRESAS (TENANTS) ----\nmodel Tenant {\n  id           String       @id @default(uuid())\n  razaoSocial  String\n  nomeFantasia String\n  cnpj         String       @unique\n  email        String\n  telefone     String?\n  plano        Plano        @default(BASICO)\n  status       StatusTenant @default(ATIVO)\n\n  // Geofencing\n  geofenceLat  Float?\n  geofenceLng  Float?\n  geofenceRaio Int    @default(200) // metros\n\n  // Configurações\n  fotoObrigatoria   Boolean @default(true)\n  geofenceAtivo     Boolean @default(false)\n  toleranciaMinutos Int     @default(5)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  usuarios  Usuario[]\n  registros RegistroPonto[]\n  escalas   Escala[]\n  ajustes   AjustePonto[]\n\n  @@map(\"tenants\")\n}\n\nenum Plano {\n  BASICO // até 10 usuários\n  PROFISSIONAL // até 50 usuários\n  ENTERPRISE // ilimitado\n}\n\nenum StatusTenant {\n  ATIVO\n  SUSPENSO\n  CANCELADO\n}\n\n// ---- USUÁRIOS ----\nmodel Usuario {\n  id       String @id @default(uuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  nome         String\n  email        String\n  pinHash      String // PIN numérico hasheado (usado no totem)\n  cargo        String?\n  departamento String?\n  role         Role    @default(COLABORADOR)\n  ativo        Boolean @default(true)\n  fotoPerfil   String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  registros     RegistroPonto[]\n  escalas       Escala[]\n  ajustesFeitos AjustePonto[]   @relation(\"AdminAjuste\")\n\n  @@unique([tenantId, email])\n  @@index([tenantId])\n  @@map(\"usuarios\")\n}\n\nenum Role {\n  SUPER_ADMIN\n  ADMIN // Gerente da empresa\n  COLABORADOR\n}\n\n// ---- REGISTROS DE PONTO ----\nmodel RegistroPonto {\n  id        String  @id @default(uuid())\n  tenantId  String\n  tenant    Tenant  @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  usuarioId String\n  usuario   Usuario @relation(fields: [usuarioId], references: [id])\n\n  tipo     TipoPonto\n  dataHora DateTime  @default(now())\n\n  // Localização\n  latitude       Float?\n  longitude      Float?\n  dentroGeofence Boolean?\n\n  // Foto\n  fotoUrl String?\n  fotoKey String? // chave no S3\n\n  // Dispositivo\n  deviceId  String?\n  ipHash    String?\n  userAgent String?\n\n  // Status\n  validado Boolean     @default(true)\n  origem   OrigemPonto @default(TOTEM)\n\n  createdAt DateTime @default(now())\n\n  ajuste AjustePonto?\n\n  @@index([tenantId, usuarioId])\n  @@index([tenantId, dataHora])\n  @@map(\"registros_ponto\")\n}\n\nenum TipoPonto {\n  ENTRADA\n  SAIDA_ALMOCO\n  RETORNO_ALMOCO\n  SAIDA\n}\n\nenum OrigemPonto {\n  TOTEM\n  APP_INDIVIDUAL\n  ADMIN_MANUAL\n}\n\n// ---- ESCALAS DE TRABALHO ----\nmodel Escala {\n  id        String  @id @default(uuid())\n  tenantId  String\n  tenant    Tenant  @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  usuarioId String\n  usuario   Usuario @relation(fields: [usuarioId], references: [id])\n\n  nome       String\n  horaInicio String // \"08:00\"\n  horaFim    String // \"17:00\"\n  diasSemana Int[] // [1,2,3,4,5] = seg a sex\n\n  cargaHorariaDiaria Float @default(8)\n  intervaloMinutos   Int   @default(60)\n\n  ativo     Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId, usuarioId])\n  @@map(\"escalas\")\n}\n\n// ---- AJUSTES DE PONTO (AUDITORIA) ----\nmodel AjustePonto {\n  id         String        @id @default(uuid())\n  tenantId   String\n  tenant     Tenant        @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  registroId String        @unique\n  registro   RegistroPonto @relation(fields: [registroId], references: [id])\n  adminId    String\n  admin      Usuario       @relation(\"AdminAjuste\", fields: [adminId], references: [id])\n\n  dataHoraOriginal DateTime\n  dataHoraNova     DateTime\n  motivo           String\n  aprovado         Boolean  @default(true)\n\n  createdAt DateTime @default(now())\n\n  @@index([tenantId])\n  @@map(\"ajustes_ponto\")\n}\n\n// ---- SUPER ADMIN (separado dos tenants) ----\nmodel SuperAdmin {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  senhaHash String\n  nome      String\n  ativo     Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  @@map(\"super_admins\")\n}\n",
